
.stage {
  width: 100%;
  padding: 8px 0;
}

.phone {
  width: min(100%, 420px);
  margin: 0 auto;
  border: 3px solid #21313a;
  border-radius: 30px;
  padding: 8px;
  background: linear-gradient(145deg, #d6ecf2 0%, #b8d4df 100%);
  box-shadow: 0 10px 28px rgba(31, 54, 66, 0.25);
  aspect-ratio: 9 / 19.5;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.notch {
  width: 42%;
  height: 18px;
  margin: 0 auto;
  border-radius: 0 0 12px 12px;
  background: #19252c;
}

.screen {
  flex: 1;
  border-radius: 22px;
  border: 1px solid rgba(26, 45, 55, 0.35);
  padding: 10px;
  background:
    radial-gradient(circle at 10% 10%, rgba(255, 255, 255, 0.75), transparent 35%),
    linear-gradient(180deg, #f5fcff 0%, #e8f3f8 100%);
  display: flex;
  flex-direction: column;
  gap: 10px;
  overflow: hidden;
  font-family: 'Noto Sans SC', 'PingFang SC', 'Microsoft YaHei', sans-serif;
  color: #21313a;
}

.sysbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.2px;
}

.sys-icons {
  display: flex;
  gap: 8px;
}

.role-panel {
  border-radius: 14px;
  border: 1px solid #95b8c7;
  background: rgba(255, 255, 255, 0.75);
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.role-main h2 {
  margin: 0;
  font-size: 17px;
}

.role-main p {
  margin: 2px 0 0;
  font-size: 12px;
  color: #37515f;
}

.chips {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.chips span {
  border-radius: 999px;
  padding: 3px 8px;
  background: #d9ecf4;
  font-size: 11px;
}

.chat-panel {
  flex: 1;
  border-radius: 14px;
  border: 1px solid #95b8c7;
  background: rgba(255, 255, 255, 0.84);
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.chat-title {
  font-size: 12px;
  font-weight: 700;
  color: #2d4552;
}

.bubble {
  max-width: 90%;
  border-radius: 12px;
  padding: 7px 10px;
  font-size: 12px;
  line-height: 1.42;
  animation: rise-in 0.45s ease both;
}

.bubble .name {
  font-size: 11px;
  font-weight: 700;
  opacity: 0.85;
  margin-bottom: 2px;
}

.bubble p {
  margin: 0;
  word-break: break-word;
}

.bubble.user {
  margin-left: auto;
  background: #d3efe2;
  border: 1px solid #87bda2;
}

.bubble.assistant {
  margin-right: auto;
  background: #e8f0ff;
  border: 1px solid #9eb4de;
}

.bubble.system {
  margin: 0 auto;
  background: #f5f7da;
  border: 1px solid #c8cd97;
}

.fade-1 {
  animation: rise-in 0.3s ease both;
}

.fade-2 {
  animation: rise-in 0.45s ease both;
}

.fade-3 {
  animation: rise-in 0.6s ease both;
}

@keyframes rise-in {
  from {
    opacity: 0;
    transform: translateY(8px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}
